#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MOD=1e8,MAXN=1e1+5,MAXM=1<<14;
int m,n,g[MAXN],cnt=0,s[MAXM],f[MAXM][MAXM],ans;
bool check_one(int x)//行内合法
{
    return (!(x&(x>>1)));
}
bool check_two(int x,int y)//行间兼容
{
    return (!(x&y));
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    m=read(),n=read();
    for(int i=1;i<=m;++i)
    {
        for(int j=1;j<=n;++j)
        {
            g[i]=(g[i]<<1)+read();
        }
    }
    for(int i=0;i<(1<<n);++i)
    {
        if(check_one(i))
        {
            s[cnt++]=i;
        }
    }//cout<<cnt;
    f[0][0]=1;
    for(int i=1;i<=m+1;++i)
    {
        for(int a=0;a<cnt;++a)
        {
            for(int b=0;b<cnt;++b)
            {
                if(check_two(s[a],s[b])&&((s[a]&g[i])==s[a]))
                {
                    f[i][a]=(f[i-1][b]+f[i][a])%MOD;
                }
            }
        }
    }
    ans=f[m+1][0];
    write(ans);
	return false;
}
